diff --git a/BitPantry.CommandLine.Tests.Remote.SignalR/ServerTests/StatCommandTests.cs b/BitPantry.CommandLine.Tests.Remote.SignalR/ServerTests/StatCommandTests.cs
index 02260df..58a67e2 100644
